    89→GDScriptDataType GDScriptCompiler::_gdtype_from_datatype(const GDScriptParser::DataType &p_datatype, GDScript *p_owner, bool p_handle_metatype) {
    90→	if (!p_datatype.is_set() || !p_datatype.is_hard_type() || p_datatype.is_coroutine) {
    91→		return GDScriptDataType();
    92→	}
    93→
    94→	GDScriptDataType result;
    95→	result.has_type = true;
    96→
    97→	switch (p_datatype.kind) {
    98→		case GDScriptParser::DataType::VARIANT: {
    99→			result.has_type = false;
   100→		} break;
   101→		case GDScriptParser::DataType::BUILTIN: {
   102→			result.kind = GDScriptDataType::BUILTIN;
   103→			result.builtin_type = p_datatype.builtin_type;
   104→		} break;
   105→		case GDScriptParser::DataType::NATIVE: {
   106→			if (p_handle_metatype && p_datatype.is_meta_type) {
   107→				result.kind = GDScriptDataType::NATIVE;
   108→				result.builtin_type = Variant::OBJECT;
   109→				// Fixes GH-82255. `GDScriptNativeClass` is obtainable in GDScript,
   110→				// but is not a registered and exposed class, so `GDScriptNativeClass`
   111→				// is missing from `GDScriptLanguage::get_singleton()->get_global_map()`.
   112→				//result.native_type = GDScriptNativeClass::get_class_static();
   113→				result.native_type = Object::get_class_static();
   114→				break;
   115→			}
   116→
   117→			result.kind = GDScriptDataType::NATIVE;
   118→			result.builtin_type = p_datatype.builtin_type;
   119→			result.native_type = p_datatype.native_type;
   120→
   121→#ifdef DEBUG_ENABLED
   122→			if (unlikely(!GDScriptLanguage::get_singleton()->get_global_map().has(result.native_type))) {
   123→				ERR_PRINT(vformat(R"(GDScript bug: Native class "%s" not found.)", result.native_type));
   124→				result.native_type = Object::get_class_static();
   125→			}
   126→#endif
   127→		} break;
   128→		case GDScriptParser::DataType::SCRIPT: {
   129→			if (p_handle_metatype && p_datatype.is_meta_type) {
   130→				result.kind = GDScriptDataType::NATIVE;
   131→				result.builtin_type = Variant::OBJECT;
   132→				result.native_type = p_datatype.script_type.is_valid() ? p_datatype.script_type->get_class() : Script::get_class_static();
   133→				break;
   134→			}
   135→
   136→			result.kind = GDScriptDataType::SCRIPT;
   137→			result.builtin_type = p_datatype.builtin_type;
   138→			result.script_type_ref = p_datatype.script_type;
   139→			result.script_type = result.script_type_ref.ptr();
   140→			result.native_type = p_datatype.native_type;
   141→		} break;
   142→		case GDScriptParser::DataType::CLASS: {
   143→			if (p_handle_metatype && p_datatype.is_meta_type) {
   144→				result.kind = GDScriptDataType::NATIVE;
   145→				result.builtin_type = Variant::OBJECT;
   146→				result.native_type = GDScript::get_class_static();
   147→				break;
   148→			}
   149→
   150→			result.kind = GDScriptDataType::GDSCRIPT;

